mapper.sql:
q.course_id = #{courseId}
AND q.deleted = 0

    AND (
        (
            q.review_status = 'APPROVED'
            AND (q.visibility IS NULL OR q.visibility != 'false')
        )
        OR q.creator_id = #{viewerId}
    )

mapper.select:
SELECT q.*
FROM t_question q
WHERE


    AND q.type = #{type}


    AND q.review_status = #{reviewStatus}


ORDER BY q.created_at DESC, q.id DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(1)
FROM t_question q
WHERE


    AND q.type = #{type}


    AND q.review_status = #{reviewStatus}
